// ============================================================================
// ⚙️ Construire les URLs de recherche pour CE jeune
// Input : données du jeune passées par le workflow parent
// ============================================================================

const inputData = $('⚡ Déclenché par Koda WA').first().json;
const token = $('🔐 Token France Travail').first().json.access_token;

const jeune = inputData.jeune || inputData;
const dept = (jeune.departement || '75').trim();

// Coordonnées par département
const deptCoords = {
  '06': { lat: 43.7102, lon: 7.2620 },
  '13': { lat: 43.2965, lon: 5.3698 },
  '33': { lat: 44.8378, lon: -0.5792 },
  '34': { lat: 43.6110, lon: 3.8767 },
  '35': { lat: 48.1173, lon: -1.6778 },
  '44': { lat: 47.2184, lon: -1.5536 },
  '59': { lat: 50.6292, lon: 3.0573 },
  '69': { lat: 45.7640, lon: 4.8357 },
  '75': { lat: 48.8566, lon: 2.3522 },
  '77': { lat: 48.5272, lon: 2.6987 },
  '78': { lat: 48.8014, lon: 2.1301 },
  '89': { lat: 47.7973, lon: 3.5674 },
  '91': { lat: 48.6293, lon: 2.4396 },
  '92': { lat: 48.8283, lon: 2.2399 },
  '93': { lat: 48.9100, lon: 2.4200 },
  '94': { lat: 48.7904, lon: 2.4753 },
  '95': { lat: 49.0354, lon: 2.0733 }
};

const coords = deptCoords[dept] || deptCoords['75'];

// Parser les codes ROME
const romesStr = (jeune.codes_rome_suggeres || 'M1805').trim();
const romes = romesStr.split(',').map(r => r.trim()).filter(r => r.length > 0);

// Construire les URLs
const ft_url = `https://api.francetravail.io/partenaire/offresdemploi/v2/offres/search?departement=${dept}&distance=20&codeROME=${romes.join(',')}&range=0-149`;
const lba_url = `https://api.apprentissage.beta.gouv.fr/api/job/v1/search?latitude=${coords.lat}&longitude=${coords.lon}&radius=25&romes=${romes.join(',')}`;

return [{
  json: {
    jeune: {
      airtable_id: jeune.airtable_id,
      prenom: jeune.prenom,
      codes_rome_suggeres: romesStr,
      departement: dept,
      ville: jeune.ville,
      niveau_francais_declare: jeune.niveau_francais_declare,
      classe: jeune.classe,
      disponibilite: jeune.disponibilite,
      secteurs_interet: jeune.secteur_vise || jeune.secteurs_interet,
      besoins: jeune.besoins,
      attentes_mentor: jeune.attentes_mentor,
      mna: jeune.mna,
      secteur_vise: jeune.secteur_vise,
      skills_inferees: '',
      frein_langue: false
    },
    romes_originaux: romes,
    romes_elargis: romes,
    token: token,
    ft_url: ft_url,
    lba_url: lba_url,
    wa_phone: inputData.wa_phone,
    phoneNumberId: inputData.phoneNumberId || '1107773802412902'
  }
}];

// ============================================================================
// 🎯 SCORING SIMPLIFIÉ — top offres pour envoi WA immédiat
// ============================================================================

const ftData = $('📡 France Travail').first().json;
const lbaData = $('📡 La Bonne Alternance').first().json;
const jeuneData = $('⚙️ Construire requêtes').first().json;
const jeune = jeuneData.jeune;

const deptJeune = (jeune.departement || '').trim();
const romesOriginaux = (jeune.codes_rome_suggeres || '').split(',').map(r => r.trim());
const PETITE_COURONNE = ['75','92','93','94'];
const IDF = ['75','92','93','94','77','78','91','95'];

// Score offre FT
function scoreOffre(o) {
  let score = 0;
  const romeOffre = o.romeCode || '';
  if (romesOriginaux.includes(romeOffre)) score += 25;
  else score += 10;
  if (o.experienceExige === 'D' || o.experienceExige === 'S') score += 20;
  const deptOffre = (o.lieuTravail?.codePostal || '').substring(0, 2);
  if (deptOffre === deptJeune) score += 15;
  else if (PETITE_COURONNE.includes(deptOffre) && PETITE_COURONNE.includes(deptJeune)) score += 10;
  else if (IDF.includes(deptOffre) && IDF.includes(deptJeune)) score += 5;
  if ((o.langues || []).length === 0) score += 10;
  if ((o.permis || []).length === 0) score += 5;
  const entreprise = o.entreprise?.nom || '';
  if (entreprise && entreprise !== 'Non communiqué') score += 3;
  return score;
}

// Scorer les offres FT
const offresFT = (ftData.resultats || []).map(o => ({
  source: 'France Travail',
  offre_id: o.id,
  titre: o.intitule,
  entreprise: o.entreprise?.nom || 'Entreprise confidentielle',
  lieu: o.lieuTravail?.libelle || '',
  type_contrat: o.typeContratLibelle || o.typeContrat || '',
  url_offre: o.origineOffre?.urlOrigine || `https://candidat.francetravail.fr/offres/recherche/detail/${o.id}`,
  score: scoreOffre(o)
})).filter(o => o.score >= 45).sort((a, b) => b.score - a.score);

// Scorer les jobs LBA
const jobsLBA = (lbaData.jobs || []).map(j => ({
  source: 'La Bonne Alternance',
  offre_id: j.identifier?.partner_job_id || j.identifier?.id || '',
  titre: j.offer?.title || '',
  entreprise: j.workplace?.name || 'Entreprise confidentielle',
  lieu: j.workplace?.location?.city || '',
  type_contrat: (j.contract?.type || []).join(', '),
  url_offre: j.apply?.url || '',
  score: 55
}));

const topOffres = [...offresFT.slice(0, 7), ...jobsLBA.slice(0, 3)].slice(0, 10);

// Formater le message WhatsApp directement (pas besoin de Haiku pour le temps réel)
const prenom = jeune.prenom || 'toi';
let waMessage = '';

if (topOffres.length === 0) {
  waMessage = `J'ai cherche dans ta zone et ton secteur mais je n'ai pas encore trouve d'offres qui collent parfaitement. Je continue a chercher et je te previens des que j'ai quelque chose !`;
} else {
  waMessage = `J'ai trouve ${topOffres.length} offre${topOffres.length > 1 ? 's' : ''} pour toi :\n\n`;
  topOffres.slice(0, 5).forEach((o, i) => {
    waMessage += `${i + 1}. ${o.titre}\n`;
    waMessage += `   ${o.entreprise} - ${o.lieu}\n`;
    waMessage += `   ${o.type_contrat}\n`;
    if (o.url_offre) waMessage += `   ${o.url_offre}\n`;
    waMessage += `\n`;
  });
  waMessage += `Tu es interesse par une de ces offres ? Dis-moi le numero et je t'aide a postuler !`;
}

return [{
  json: {
    wa_phone: jeuneData.wa_phone,
    phoneNumberId: jeuneData.phoneNumberId,
    messageWhatsApp: waMessage,
    topOffres: topOffres.slice(0, 5),
    jeune: jeune,
    debug: {
      nb_ft: (ftData.resultats || []).length,
      nb_lba_jobs: (lbaData.jobs || []).length,
      nb_total_scored: topOffres.length
    }
  }
}];
